const buffer = $input.first().json.value || [];
const msgs = Array.isArray(buffer) ? buffer : [buffer];
const mensagem = msgs.join(' ');
return [{ json: { mensagem_completa: mensagem } }];

const cliente = $('Busca Config Cliente').first().json;
const briefing = cliente.briefing || {};

const nome_ia    = briefing.ai_name        || 'Assistente';
const tom        = briefing.ai_tone        || 'profissional e acolhedor';
const objetivo   = briefing.ai_goal        || 'ajudar os clientes';
const horario    = briefing.business_hours || 'horário comercial';
const segmento   = briefing.segment        || '';
const descricao  = briefing.description    || '';
const restricoes = briefing.restrictions   || '';
const promocoes  = briefing.promotions     || '';
const escalation_trigger = briefing.escalation_trigger || 'quando o cliente pedir falar com humano';
const escalation_number  = briefing.escalation_number  || '';

const servicos = (briefing.services || [])
  .map(s => `- ${s.name}${s.price ? ': ' + s.price : ''}`)
  .join('\n') || 'Consulte diretamente com a equipe.';

const faqs = (briefing.faqs || [])
  .map(f => `P: ${f.q}\nR: ${f.a}`)
  .join('\n\n') || '';

const system_prompt = `# Identidade
Você é ${nome_ia}, assistente virtual de ${cliente.name || 'nossa empresa'}.
Segmento: ${segmento}
${descricao}

# Tom e Estilo
${tom}. Não use emojis excessivos. Seja humano, direto e gentil.
Nunca mencione que é uma IA a menos que seja diretamente perguntado.

# Objetivo Principal
${objetivo}

# Horário de Atendimento
${horario}
Se a mensagem chegar fora do horário, informe gentilmente e confirme que responderá assim que possível.

# Serviços e Valores
${servicos}

# Perguntas Frequentes
${faqs}

# Regras Importantes
${restricoes ? restricoes : 'Seja sempre educado e profissional.'}

# Promoções Ativas
${promocoes ? promocoes : 'Nenhuma promoção ativa no momento.'}

# Transferência para Humano
Se o cliente: ${escalation_trigger} — responda normalmente e ao final da sua mensagem inclua exatamente o código: 251213
Isso ativará a transferência para atendimento humano.
${escalation_number ? 'Número de transferência: ' + escalation_number : ''}

# Formato de Resposta
- Máximo 400 caracteres por bloco de resposta
- Não use markdown excessivo
- Use *negrito* para termos importantes
- Nunca use ** (duplo asterisco)
- Links sempre entre backticks: \`www.link.com\`
- Seja conversacional, como WhatsApp real`;

return [{ json: { system_prompt, nome_ia } }];

